// Validar que el payload de Meta venga del origen correcto.
// Meta Cloud API incluye el verify_token en el campo hub.verify_token
// para la verificacion inicial (GET), pero para eventos POST no hay
// token de verificacion — se valida con X-Hub-Signature-256 si META_APP_SECRET esta configurado.
//
// Para eventos POST: validar firma HMAC si el header esta presente.
const crypto = require('crypto');

const rawBody   = $input.first().binary?.data ? Buffer.from($input.first().binary.data, 'base64').toString('utf8') : JSON.stringify($input.first().json);
const sigHeader = $input.first().headers['x-hub-signature-256'] || '';

// Si hay header de firma, validarla con META_CLOUD_API_TOKEN como secret
// (en produccion deberia ser META_APP_SECRET — mismo concepto)
if (sigHeader) {
  const secret = $env.META_CLOUD_API_TOKEN;
  if (secret) {
    const receivedHex = sigHeader.startsWith('sha256=') ? sigHeader.slice(7) : sigHeader;
    let receivedBuf;
    try { receivedBuf = Buffer.from(receivedHex, 'hex'); } catch (e) { throw new Error('Firma Meta malformada'); }
    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(rawBody);
    const expectedBuf = Buffer.from(hmac.digest('hex'), 'hex');
    if (receivedBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(receivedBuf, expectedBuf)) {
      throw new Error('Meta CTWA: X-Hub-Signature-256 invalida');
    }
  }
}

return $input.all();

// Extraer objeto referral con ctwa_clid del webhook de Meta Cloud API
// Estructura tipica del payload de Meta para mensajes de WhatsApp con CTWA:
// { entry: [{ changes: [{ value: { messages: [{ referral: { ctwa_clid, source_url, source_id, ... }, from: '<phone>' } }] } }] }] }

function normalizeE164(raw) {
  if (!raw) return null;
  let digits = String(raw).replace(/[^\d+]/g, '');
  if (digits.startsWith('+')) {
    const clean = '+' + digits.slice(1).replace(/\D/g, '');
    return (clean.length >= 8 && clean.length <= 16) ? clean : null;
  }
  if (/^3\d{9}$/.test(digits)) return '+57' + digits;
  if (/^57\d{10}$/.test(digits)) return '+' + digits;
  if (digits.length >= 7 && digits.length <= 15) return '+' + digits;
  return null;
}

const payload = $input.first().json;
const results = [];

const entries = Array.isArray(payload.entry) ? payload.entry : [];

for (const entry of entries) {
  const changes = Array.isArray(entry.changes) ? entry.changes : [];
  for (const change of changes) {
    const value = change.value || {};
    const messages = Array.isArray(value.messages) ? value.messages : [];
    for (const msg of messages) {
      const referral = msg.referral;
      if (!referral || !referral.ctwa_clid) continue;

      const phone = normalizeE164(msg.from);
      if (!phone) continue;

      results.push({
        ctwa_clid:     String(referral.ctwa_clid).substring(0, 500),
        phone,
        ad_id:         referral.source_id ? String(referral.source_id).substring(0, 100) : null,
        ad_name:       referral.headline  ? String(referral.headline).substring(0, 500)  : null,
        source_url:    referral.source_url ? String(referral.source_url).substring(0, 2048) : null,
        headline:      referral.headline  ? String(referral.headline).substring(0, 500)  : null,
        body_text:     referral.body      ? String(referral.body).substring(0, 5000)     : null,
        clicked_at:    new Date().toISOString()
      });
    }
  }
}

if (results.length === 0) {
  // Payload sin CTWA — responder 200 igualmente (Meta reintentar si no responde)
  return [{ json: { _skip: true } }];
}

return results.map(r => ({ json: r }));
